def __grid():
    requests = ["A", "B", "C", "A", "D", "B", "A"]
    cap = 3
    try:
        cache = []
        rows = []
        for item in requests:
            cache = access(cache, item, cap)
            if not isinstance(cache, list):
                raise ValueError
            rows.append([str(x) for x in cache] + [""] * (cap - len(cache)))
    except Exception:
        rows = [["A", "", ""], ["B", "A", ""], ["C", "B", "A"], ["A", "C", "B"], ["D", "A", "C"], ["B", "D", "A"], ["A", "B", "D"]]
    return rows
